        encoded = self._encode_vhost(vhost.name)
        payload = {}
        if vhost.description:
            payload["description"] = vhost.description
        if vhost.tags:
            payload["tags"] = ",".join(vhost.tags)

        response = self.session.put(
            f"{self.base_url}/vhosts/{encoded}",
            data=json.dumps(payload),
        )
        return self._handle_response(response, f"Create vhost '{vhost.name}'")

